effect.script:
function animate(env,el,p,pprev) {

    let prefix = el.text.slice(0, Math.round(el.text.length * p.start));
    let middle = el.text.slice( Math.round(el.text.length * p.start), Math.round(el.text.length * p.end));
    let suffix = el.text.slice(Math.round(el.text.length * p.end));

    //AM.log(`textrand: el.text="${el.text}" prefix="${prefix}" middle="${middle}" suffix="${suffix}" `);

    let randomized = "";
    let charset = p.charset;

    for (let i = 0; i < middle.length; i++) {
        let ch = middle.charAt(i);
        //AM.log(`textrand:   i=${i} ch=${ch} r=${AM.simplexNoise(i*7.3921, p.seed)} p.amount=${p.amount}" `);
        if( (AM.simplexNoise(i*7.3921, p.seed)+1)/2 >= p.amount || (p.preserveSpace && ch==" ") ) {
            randomized = randomized + ch;
        } else {
            let chars = "";
            if( charset == 0 ) {
                chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZ";
            } else if (charset == 1 ) {
                chars = "abcdefghijklmnopqrstuvwxyz";
            } else if (charset == 2 ) {
                chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz";
            } else if (charset == 3 ) {
                chars = "0123456789";
            } else if (charset == 4 ) {
                chars = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz";
            } else if (charset == 5 ) {
                chars = el.text;
            } else if (charset == 6 ) {
                chars = "*";
            } else if (charset == 7 ) {
                chars = "•";
            } else if (charset == 8 ) {
                chars = "_";
            } else if (charset == 9 ) {
                chars = " ";
            } else if (charset == 10 ) {
                chars = "◊";
            } else if (charset == 11 ) {
                chars = "-";
            } else if (charset == 12 ) {
                chars = "+=-!@#$%^*()[]{}:;\/,.<>~`";
            } else if (charset == 13 ) {
                chars = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz+=-!@#$%^*()[]{}:;\/,.<>~`";
            } else if (charset == 14 ) {
                chars = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyzΩµ+=-!@#$%^*()[]{}:;\/,.<>~`∈∑ΨΦδγβϰψπλ∞≤≥≠àãëæñüóç¶‽∙✓✗➝←";
            }

            randomized = randomized + chars.charAt(Math.floor(( (AM.simplexNoise(i*7.3921, p.evo + 0.5)+1)*92.1734*chars.length) % chars.length));
        }
    }

    el.text = prefix + randomized + suffix;

    return el;
}
